export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:10。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "往鐘樓的路。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨比一個小時前更大了。不是細雨。是那種打在臉上會痛的雨。風從海面上吹過來，把雨切成斜的，打在校服上，布料貼著皮膚，冷到骨頭裡。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言走在石板路上。一步。一步。一步。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "假相機包掛在右肩。背帶勒進鎖骨。重量不對——太輕了。但形狀對。在監控畫面裡，在遠處校安的眼裡，在邵叔透過任何一個鏡頭看到的畫面裡——這就是一個相機包。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在看。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不一定親眼看。可能透過監控。可能透過校安回報。可能透過林主任。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他一定在看。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他看到一個學生。穿校服。帶著相機包。往鐘樓方向走。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會判斷——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧言帶著密碼線和疑似相機包，準備走鐘樓備用傳輸線。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和他被餵到的情報吻合。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）餌要像餌。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他調整了一下步伐。不快。不慢。像一個有目的的人。像一個知道自己要去哪裡的人。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是跑。跑會讓人警覺。走。穩穩地走。像去赴一個只有自己知道的約。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "石板路在前方分岔。左邊通往禮堂正門。右邊通往鐘樓。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往右拐。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拐彎的瞬間，他看見了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它站在雨霧裡。和第一章一模一樣。和每一輪一模一樣。灰色的石頭。黑色的窗洞。頂部的鐘面在夜裡看不見指針，只剩一個圓形的輪廓，像一隻閉著的眼睛。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨打在石頭上。聲音很大。像無數根手指同時敲在桌面上。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "胃裡翻了一下。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是冷。不是痛。是一種更舊的東西。從身體最深的地方翻上來。像十年前的煙味。像七歲那年的焦味。像——", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）墜落。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他記得這個感覺。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一章。22:22。鐘樓停電。他站在鐘樓的樓層邊緣。背後有一隻手。然後——", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "失重。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是跳下去的那種失重。是被推下去的那種。身體在空中。風從下面灌上來。胃裡的東西全往上湧。然後——", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "什麼都沒了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我死過這裡。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一章。我死在這裡。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的腳步慢了半拍。就半拍。然後恢復了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨打在臉上。他沒有擦。讓它打著。讓冷意把他從記憶裡拉回來。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不一樣。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那次——我是被引上去的。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）匿名訊息叫我不要上去。我偏不信。我把訊息拿給邵叔。邵叔說「交給我」。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後他把我引到鐘樓。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後他推了我。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那次——我沒有選擇。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不知道那是陷阱。我不知道他是誰。我以為他在保護我。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他繼續走。石板路在腳下延伸。每一步都在靠近鐘樓。每一步都在靠近第一章的死亡地點。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一次——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道那是陷阱。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道他是誰。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道他會在 22:22 等著。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次，不是他引我上去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是我自己走回來的。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "風從鐘樓的方向吹過來。帶著石頭的氣味。帶著雨的氣味。帶著鐵鏽的氣味——鐘樓外牆的鐵件在潮濕裡氧化，每一輪都是這個味道。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走近了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓的陰影蓋過來。像一隻手。從頭頂壓下來。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身體在抗拒。每一塊肌肉都在說：不要過去。不要靠近。你死過那裡。你知道那裡有什麼。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他沒有停。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前七輪，我一直在逃。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）逃鐘樓。逃校務車。逃醫務室。逃地下泵房。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）逃了七次。死了七次。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）逃不了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為命運。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是因為——只要他在那裡，只要他手上有權限，只要他能把安全流程變成武器——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）逃到哪裡都一樣。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停下來了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是因為害怕。是因為到了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓的入口。石拱門。鐵門半開著——和每一輪一樣。校慶期間鐘樓外圍開放參觀，但內部上鎖。鐵門的鎖是舊的。他知道。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在拱門外面。雨從背後打過來。假相機包在肩上。裡面只有泡棉。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔現在應該已經知道了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧言在鐘樓入口。帶著相機包。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會判斷——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧言要進鐘樓。要用備用傳輸線。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會等 22:22。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會在停電的時候動手。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和第一章一模一樣。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這次不一樣。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他抬頭。看著鐘樓。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "石頭。黑窗。閉著的鐘面。雨霧裡的輪廓。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "和第一章一模一樣。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他不一樣了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一章。我是被引上來的。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不知道那是死亡地點。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我以為有人在保護我。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道這是死亡地點。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道誰在背後。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我選擇回到這裡。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為不怕。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是因為——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果我讓這個地方永遠是「我死過的地方」——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）它就永遠是他的武器。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但如果我回到這裡。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果我站在這裡。然後離開。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果我讓他以為我在這裡死了——但其實我走了——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這個地方就不再是死亡地點。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）它只是一座舊鐘樓。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸了一口氣。雨灌進嘴裡。他沒有吐。嚥下去了。冷的。像吞了一口海水。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:15。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還有七分鐘。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）進去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓他看見我進去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:22。停電。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越在背面。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）假人。背包。手機。黑雨衣。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我從服務走廊走。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會看到「我」從鐘樓背面掉下去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會判斷——顧言死了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後他會轉向星棠。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他到時候會發現——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我已經不在鐘樓了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我在禮堂。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我在直播線旁邊。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我在他背後。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手伸進口袋。摸到了手機。手機螢幕是暗的。等一下，這支手機會放進背包裡，綁在假人身上。邵叔會透過手機定位確認「顧言在鐘樓背面」。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但不是現在。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現在，他需要手機做最後一件事。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他掏出手機。打開。點進那則匿名訊息。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "今晚 22:22，鐘樓會停電。不要上去。不要把相機交給任何大人。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第八次了。同樣的字。同樣的格式。同樣的警告。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著「不要上去」四個字。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要上去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一次——我上去了。死了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二次到第七次——我沒上去。但還是死了。死在校務車。死在醫務室。死在地下泵房。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）避開鐘樓沒有用。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為他不止鐘樓這一個陷阱。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一次——", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我上去。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為訊息錯了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是因為——我已經不是那個會被引上去的人了。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機收起來。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:17。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在鐘樓入口的拱門外面。雨從背後打過來。假相機包在肩上。鐘樓在面前。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "和第一章一模一樣的畫面。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但方向不同了。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一章，他走進鐘樓的時候，是因為相信有人會保護他。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次，他走進鐘樓，是因為知道誰要殺他。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）走吧。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓這個地方失效。", background: Background.Chapter_8_Ch8_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他邁步。穿過拱門。走進鐘樓的陰影裡。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨聲在拱門下面變了。從開闊的、打在石板上的聲音，變成迴盪的、在石牆之間反射的聲音。像走進了一個巨大的共鳴箱。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:18。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還有四分鐘。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往裡走。每一步都在靠近樓梯。每一步都在靠近22:22。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "背後，雨還在下。禮堂方向的燈光在雨霧裡模糊成一團暖色。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。", background: Background.Chapter_8_Ch8_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次，他不回頭。", background: Background.Chapter_8_Ch8_Act12_S0 },
];
